import{_ as r,o as t,c as a,ag as i}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"generator-verifier-pattern","description":"","frontmatter":{"title":"generator-verifier-pattern","concept":"生成验证者模式","concept_id":"generator-verifier-pattern","aliases":[],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md"],"related_concepts":["[[narrow-scope-ai-review]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/generator-verifier-pattern.md","filePath":"wiki/concepts/generator-verifier-pattern.md","lastUpdated":null}'),n={name:"wiki/concepts/generator-verifier-pattern.md"};function o(c,e,s,l,p,h){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="生成验证者模式-generator-verifier-pattern" tabindex="-1">生成验证者模式 (Generator-Verifier Pattern) <a class="header-anchor" href="#生成验证者模式-generator-verifier-pattern" aria-label="Permalink to &quot;生成验证者模式 (Generator-Verifier Pattern)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在多 Agent 分工中，一类针对“高质量产出要求”的典型编排网络。包含一个内容生成 Agent（Generator）以及一个或多个专门负责拿固定标准审查结果并驳回的评判 Agent（Verifier）。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>对抗性校验</strong>：质量控制的正确设计是让一个 Agent 专门找另一个 Agent 的问题，而不是“接力传递工作成果”。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Multi-agent coordination patterns_ Five approaches and when to use them.html">[Agent_Architecture] Multi-agent coordination patterns_ Five approaches and when to use them.md</a>）</li><li><strong>客观的拒绝标准</strong>：Verifier 需要被配置非常明确的准入规则，例如静态分析要求、测试覆盖率或业务硬性指标，否则会陷入无休止且主观的自我纠错循环。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>非常适合“写代码 + 写配套单测并在虚拟盒里运行”这类的闭环验证。如果 Verifier 发现报错或不符，直接把反馈推回给 Generator。限制此环路通常配置为 3-5 次。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/narrow-scope-ai-review.html">narrow-scope-ai-review</a> — 在此架构中 Verifier 所具体执行的战术动作。</li></ul>',9)])])}const u=r(n,[["render",o]]);export{_ as __pageData,u as default};
